// ══════════════════════════════════════════════════════════
// CONFIGURAÇÃO — alterar somente esta seção
// ══════════════════════════════════════════════════════════
const PAGARME_SECRET_KEY   = 'sk_G5ajdgqcpyuyPm4q';
const PAGARME_API_URL      = 'https://api.pagar.me/core/v5/orders';
const SUCCESS_URL          = 'https://tannat-y-cordero-en-s-o-paulo.vercel.app/success';
const MAX_QTY              = 10;
// ══════════════════════════════════════════════════════════

const body = $input.first().json.body || $input.first().json;

// Validações
if (!body.email || !body.email.includes('@'))           throw new Error('Email inválido');
if (!body.first_name || body.first_name.trim() === '')  throw new Error('Falta nome');
if (!body.quantity)                                      throw new Error('Falta quantidade');
if (!body.amount || body.amount <= 0)                   throw new Error('Monto inválido');

const qty           = Math.min(Math.max(parseInt(body.quantity, 10) || 1, 1), MAX_QTY);
const unitPrice     = Math.round((body.amount / body.quantity) * 100); // converte a centavos
const totalCentavos = unitPrice * qty;
const eventName     = body.event || 'Evento Senderos';
const currency      = body.currency || 'BRL';

// IDs
const ts      = Date.now();
const rand    = Math.random().toString(36).slice(2, 6).toUpperCase();
const orderId = 'TANNAT-' + (body.country || 'BR') + '-' + ts + '-' + rand;

// Customer
const fullName = (body.first_name + ' ' + (body.last_name || '')).trim();
const docClean = body.document ? body.document.replace(/[^0-9]/g, '') : null;

// Telefone — detecta country code do próprio número
const phoneRaw    = (body.phone || '').replace(/\s|-/g, '');
const phoneDigits = phoneRaw.replace(/[^0-9]/g, '');

const phonePrefixes = [
  { code: '598', country: 'UY' },
  { code: '549', country: 'AR' },
  { code: '56',  country: 'CL' },
  { code: '57',  country: 'CO' },
  { code: '52',  country: 'MX' },
  { code: '51',  country: 'PE' },
  { code: '54',  country: 'AR' },
  { code: '55',  country: 'BR' },
];

let phoneCountryCode = '55';
let phoneLocal       = phoneDigits;

if (phoneRaw.startsWith('+') || phoneDigits.length > 11) {
  for (const prefix of phonePrefixes) {
    if (phoneDigits.startsWith(prefix.code)) {
      phoneCountryCode = prefix.code;
      phoneLocal       = phoneDigits.substring(prefix.code.length);
      break;
    }
  }
}

const areaCode = phoneLocal.substring(0, 2);
const phoneNum = phoneLocal.substring(2);

const selectedCountry = body.country || 'BR';

// Payload Pagar.me
const orderPayload = {
  code: orderId,
  items: [{
    amount:      unitPrice,
    description: eventName,
    quantity:    qty
  }],
  customer: {
    name:          fullName,
    email:         body.email.toLowerCase().trim(),
    type:          docClean ? 'individual' : undefined,
    document:      docClean || undefined,
    document_type: docClean ? 'CPF' : undefined,
    phones: {
      mobile_phone: {
        country_code: phoneCountryCode,
        area_code:    areaCode,
        number:       phoneNum
      }
    }
  },
  payments: [{
    payment_method: 'checkout',
    amount: totalCentavos,
    checkout: {
      customer_editable:          false,
      skip_checkout_success_page: false,
      accepted_payment_methods:   ['credit_card', 'pix'],
      success_url:                SUCCESS_URL,
      billing_address_editable:   false,
      billing_address: {
        line_1:   'Av. Brigadeiro Faria Lima, 2369',
        line_2:   'Itaim Bibi',
        zip_code: '01452922',
        city:     'São Paulo',
        state:    'SP',
        country:  'BR'
      },
      pix: { expires_in: 900 },
      credit_card: {
        capture:              true,
        statement_descriptor: 'SENDEROS SP',
        installments: [{ number: 1, total: totalCentavos }]
      }
    }
  }],
  metadata: {
    source:   'landing_tannat',
    order_id: orderId,
    country:  selectedCountry,
    phone:    body.phone || ''
  }
};

// Auth Basic (sk_xxx + ':')
const authB64 = Buffer.from(PAGARME_SECRET_KEY + ':').toString('base64');

// Linha para tabela n8n
const tableRow = {
  order_id:    orderId,
  full_name:   fullName,
  email:       body.email.toLowerCase().trim(),
  phone:       body.phone || '',
  country:     selectedCountry,
  quantity:    qty,
  amount:      totalCentavos,
  currency:    currency,
  status:      'PENDING',
  ticket_code: '',
  paid_at:     '',
  created_at:  new Date().toISOString()
};

return [{
  json: {
    api_url:     PAGARME_API_URL,
    auth_header: 'Basic ' + authB64,
    order_body:  orderPayload,
    order_id:    orderId,
    tableRow
  }
}];

const res  = $input.first().json;
const body = res.body || {};

let errorMsg = 'Erro ao processar pagamento. Tente novamente.';

if (body.message) {
  errorMsg = body.message.includes('Authorization has been denied')
    ? 'Erro de autenticação: verifique a Secret Key do Pagar.me.'
    : body.message;
}

if (body.errors && Array.isArray(body.errors) && body.errors.length > 0) {
  errorMsg = body.errors.map(e => e.message || e).join('; ');
}

return [{ json: { errorMsg, statusCode: res.statusCode, rawBody: body } }];

// ══════════════════════════════════════════════════════════
// CONFIGURAÇÃO Evolution API (WhatsApp)
// ══════════════════════════════════════════════════════════
const EVOLUTION_URL      = 'https://evolution.SEU-DOMINIO.com';
const EVOLUTION_API_KEY  = 'SUA_API_KEY_EVOLUTION';
const EVOLUTION_INSTANCE = 'SUA_INSTANCIA';
// ══════════════════════════════════════════════════════════

const payload = $input.first().json.body || $input.first().json;
const eventType = payload.type || '';

console.log('[Pagar.me Webhook] type:', eventType);

// Eventos aceitos
const PAID_EVENTS = ['order.paid', 'charge.paid', 'checkout.closed'];
const CANCEL_EVENTS = ['checkout.canceled'];

const isPaid   = PAID_EVENTS.some(e => eventType === e);
const isCanceled = CANCEL_EVENTS.some(e => eventType === e);

if (!isPaid && !isCanceled) {
  throw new Error('Evento ignorado: ' + eventType);
}

// Extrai dados do pedido — estrutura varia por tipo de evento
let order    = {};
let orderId  = '';
let phone    = '';
let customer = {};
let totalCentavos = 0;

if (eventType === 'order.paid') {
  order    = payload.data || {};
  orderId  = order.code  || order.id || '';
  customer = order.customer || {};
  phone    = (order.metadata && order.metadata.phone) ? order.metadata.phone : '';
  totalCentavos = order.amount || 0;
}

if (eventType === 'charge.paid') {
  const charge = payload.data || {};
  order    = charge.order || {};
  orderId  = order.code  || charge.code || '';
  customer = charge.customer || order.customer || {};
  phone    = (order.metadata && order.metadata.phone)
    ? order.metadata.phone
    : (charge.metadata && charge.metadata.phone) || '';
  totalCentavos = charge.amount || order.amount || 0;
}

if (eventType === 'checkout.closed') {
  const checkout = payload.data || {};
  order    = checkout.order || {};
  orderId  = order.code   || checkout.code || '';
  customer = checkout.customer || order.customer || {};
  phone    = (checkout.metadata && checkout.metadata.phone)
    ? checkout.metadata.phone
    : (order.metadata && order.metadata.phone) || '';
  totalCentavos = checkout.amount || order.amount || 0;
}

if (eventType === 'checkout.canceled') {
  const checkout = payload.data || {};
  order   = checkout.order || {};
  orderId = order.code || checkout.code || '';
  return [{ json: { action: 'CANCEL', orderId, eventType } }];
}

// Filtro: só processa pedidos do Tannat
const source = (order.metadata && order.metadata.source) || '';
if (source && source !== 'landing_tannat') {
  throw new Error('Pedido ignorado — source: ' + source);
}

if (!orderId) throw new Error('Webhook sem order_id — ignorado');
if (!phone)   throw new Error('Webhook sem phone no metadata — order: ' + orderId);

const phoneClean = phone.replace(/[^0-9]/g, '');
const fullName   = customer.name  || 'Cliente';
const firstName  = fullName.split(' ')[0];
const totalReais = (totalCentavos / 100).toFixed(2).replace('.', ',');
const paidAt     = new Date().toISOString();

return [{
  json: {
    action:          'PAY',
    eventType,
    orderId,
    phone:           phoneClean,
    fullName,
    firstName,
    totalReais,
    paidAt,
    evolutionUrl:    EVOLUTION_URL,
    evolutionApiKey: EVOLUTION_API_KEY,
    evolutionInst:   EVOLUTION_INSTANCE
  }
}];

const crypto = require('crypto');
const data   = $input.first().json;

const ticketCode = 'TKT-' + crypto.randomBytes(4).toString('hex').toUpperCase();

const qrContent  = `Evento: Tannat y Cordero SP | Ticket: ${ticketCode} | Pedido: ${data.orderId}`;
const qrImageUrl = `https://api.qrserver.com/v1/create-qr-code/?size=400x400&margin=20&data=${encodeURIComponent(qrContent)}`;

const whatsappMsg = [
  `🍷 *¡Tu reserva está confirmada!*`,
  ``,
  `Hola ${data.firstName}, todo listo para`,
  `*Tannat y Cordero en São Paulo* 🥩`,
  ``,
  `🎟 *Tu código de entrada:*`,
  `\`${ticketCode}\``,
  ``,
  `💰 Pagado: R$${data.totalReais} BRL`,
  `📍 Itaim Bibi, São Paulo`,
  ``,
  `Presentá este código o el QR adjunto en la entrada del evento.`,
  ``,
  `_¡Nos vemos pronto!_ 🙌`
].join('\n');

return [{
  json: {
    ...data,
    ticketCode,
    qrImageUrl,
    whatsappMsg
  }
}];

